function onLoad() {
	// RAJ 2020.03.19  STRY0063505 - retrieve the Shared Attachments flag from the server.
	// check the value to determine if the Related List for "Shared Attachments" should be displayed or hidden in the associated
	// "onLoad script"

	// TODO: THIS IS NOT WORKING, NOT SURE WHY
	// TRIED 'Attachments', 'Attachment', 'sys_attachment', attachment, attachments

	//alert(g_scratchpad.sharedAttachmentsFolder);
	if(g_scratchpad.sharedAttachmentsFolder == true){
		g_form.showRelatedList('sys_attachment'); //'Shared Attachment');
	}
	else{
		g_form.hideRelatedList('sys_attachment'); //'Shared Attachment');
	} 

}
